package main

import (
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"math/big"
)

const (
	tokenLength = 32
	charset     = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
)

// GenerateSessionToken generates a cryptographically secure random
// alphanumeric session token of 32 characters.
// Note: We use crypto/rand instead of math/rand for security purposes,
// as math/rand is not suitable for generating authentication tokens.
func GenerateSessionToken() (string, error) {
	result := make([]byte, tokenLength)
	charsetLen := big.NewInt(int64(len(charset)))

	for i := 0; i < tokenLength; i++ {
		randomIndex, err := rand.Int(rand.Reader, charsetLen)
		if err != nil {
			return "", fmt.Errorf("failed to generate random number: %w", err)
		}
		result[i] = charset[randomIndex.Int64()]
	}

	return string(result), nil
}

// GenerateSessionTokenHex generates a cryptographically secure random
// session token as a 32-character hex string.
func GenerateSessionTokenHex() (string, error) {
	bytes := make([]byte, tokenLength/2)
	_, err := rand.Read(bytes)
	if err != nil {
		return "", fmt.Errorf("failed to generate random bytes: %w", err)
	}
	return hex.EncodeToString(bytes), nil
}

func main() {
	token, err := GenerateSessionToken()
	if err != nil {
		fmt.Printf("Error generating token: %v\n", err)
		return
	}
	fmt.Printf("Alphanumeric Token: %s (length: %d)\n", token, len(token))

	hexToken, err := GenerateSessionTokenHex()
	if err != nil {
		fmt.Printf("Error generating hex token: %v\n", err)
		return
	}
	fmt.Printf("Hex Token:          %s (length: %d)\n", hexToken, len(hexToken))
}